    85→      background: var(--bg-section);
    86→      border: 1px solid var(--border);
    87→      border-radius: 4px;
    88→      padding: 1.25rem 1.5rem;
    89→      margin-bottom: 1rem;
    90→    }
    91→
    92→    h2 {
    93→      font-size: 0.65rem;
    94→      text-transform: uppercase;
    95→      letter-spacing: 0.16em;
    96→      color: var(--text-dim);
    97→      margin-bottom: 1rem;
    98→      padding-bottom: 0.5rem;
    99→      border-bottom: 1px solid var(--border);
   100→    }
   101→
   102→    /* ── Radio labels ── */
   103→    label {
   104→      display: flex;
   105→      align-items: center;
   106→      gap: 0.6rem;
   107→      margin-bottom: 0.4rem;
   108→      cursor: pointer;
