   205→<body>
   206→
   207→  <div class="panel">
   208→
   209→    <nav class="panel-nav">
   210→      <a href="/">&#8592; back to clock</a>
   211→      <span class="site-id">erudit0rum</span>
   212→    </nav>
   213→
   214→    <h1>clock controls</h1>
   215→
   216→    <!-- Mode -->
   217→    <section>
   218→      <h2>Mode</h2>
   219→      <label id="lbl-clock"><input type="radio" name="mode" value="clock" /> Clock</label>
   220→      <label id="lbl-countdown"><input type="radio" name="mode" value="countdown" /> Countdown</label>
   221→    </section>
   222→
   223→    <!-- Clock settings -->
   224→    <section id="section-clock">
   225→      <h2>Clock Settings</h2>
   226→      <div class="field">
   227→        <span class="field-label">UTC offset (hours)</span>
   228→        <input type="number" id="hours" min="-12" max="14" step="1" value="0" />
   229→      </div>
   230→      <p class="note">0 = Universal Time &nbsp;·&nbsp; +1 = UTC+1 &nbsp;·&nbsp; +9 = Tokyo &nbsp;·&nbsp; −5 = New York EST</p>
   231→    </section>
   232→
   233→    <!-- Countdown settings -->
   234→    <section id="section-countdown">
   235→      <h2>Countdown</h2>
   236→      <div class="field">
   237→        <span class="field-label">Time (MM:SS)</span>
   238→        <input type="text" id="countdown-time" placeholder="05:00" pattern="\d{1,2}:\d{2}" />
   239→      </div>
   240→      <p class="note">Max 99:59. Press Start to begin; press again to reset with current time value.</p>
   241→      <button id="start-btn">&#9654;&nbsp; Start / Reset</button>
   242→      <div id="status"></div>
   243→    </section>
   244→
   245→  </div>
   246→
   247→  <script>
   248→    (function () {
   249→      const ls = { get: k => localStorage.getItem(k), set: (k,v) => localStorage.setItem(k,v) };
   250→
   251→      // ── Restore saved values ────────────────────────────────────────────
   252→      const rawMode    = ls.get('clk_mode');
   253→      const savedMode  = (rawMode === 'clock' || rawMode === 'countdown') ? rawMode : 'clock';
   254→      const savedHours = ls.get('clk_hours')           || '0';
   255→      const savedTime  = ls.get('clk_countdown_time')  || '05:00';
   256→
   257→      document.querySelector(`input[value="${savedMode}"]`).checked = true;
   258→      document.getElementById('hours').value          = savedHours;
   259→      document.getElementById('countdown-time').value = savedTime;
   260→
   261→      // ── Section visibility ──────────────────────────────────────────────
   262→      function updateSections() {
   263→        const mode = document.querySelector('input[name="mode"]:checked').value;
   264→        document.getElementById('section-clock').classList.toggle('hidden', mode !== 'clock');
   265→        document.getElementById('section-countdown').classList.toggle('hidden', mode !== 'countdown');
   266→        document.getElementById('lbl-clock').classList.toggle('active', mode === 'clock');
   267→        document.getElementById('lbl-countdown').classList.toggle('active', mode === 'countdown');
   268→      }
   269→      updateSections();
   270→
   271→      // ── Event listeners ─────────────────────────────────────────────────
   272→      document.querySelectorAll('input[name="mode"]').forEach(r => {
   273→        r.addEventListener('change', () => {
   274→          ls.set('clk_mode', r.value);
   275→          updateSections();
   276→        });
   277→      });
   278→
   279→      document.getElementById('hours').addEventListener('input', e => {
   280→        ls.set('clk_hours', e.target.value);
   281→      });
   282→
   283→      document.getElementById('countdown-time').addEventListener('input', e => {
   284→        ls.set('clk_countdown_time', e.target.value);
   285→      });
   286→
   287→      // ── Start / Reset countdown ──────────────────────────────────────────
   288→      document.getElementById('start-btn').addEventListener('click', () => {
   289→        const raw = document.getElementById('countdown-time').value.trim() || '05:00';
   290→        const parts = raw.split(':');
   291→        const mm = Math.min(99, parseInt(parts[0], 10) || 0);
   292→        const ss = Math.min(59, parseInt(parts[1], 10) || 0);
   293→        const totalMs = (mm * 60 + ss) * 1000;
   294→
   295→        ls.set('clk_countdown_time', `${String(mm).padStart(2,'0')}:${String(ss).padStart(2,'0')}`);
   296→        ls.set('clk_countdown_end', Date.now() + totalMs);
   297→        ls.set('clk_mode', 'countdown');
   298→
   299→        document.querySelector('input[value="countdown"]').checked = true;
   300→        updateSections();
   301→
   302→        const endTime = new Date(Date.now() + totalMs);
   303→        document.getElementById('status').textContent =
   304→          `Started — ends at ${endTime.toLocaleTimeString()}`;
   305→      });
   306→    })();
   307→  </script>
   308→
   309→</body>
   310→</html>
