     1→/**
     2→ * Global CSS
     3→ * Reusable styles: typography, links, forms, 12-column grid
     4→ * Safe to defer loading (non-critical path)
     5→ */
     6→
     7→@charset "UTF-8";
     8→
     9→/* ===== BASE TYPOGRAPHY ===== */
    10→p {
    11→  font-size: var(--font-size-body);
    12→  line-height: 1.6;
    13→}
    14→
    15→h1 { font-size: var(--font-size-h1); }
    16→h2 { font-size: var(--font-size-h2); }
    17→h3 { font-size: var(--font-size-h3); }
    18→
    19→/* ===== LINKS ===== */
    20→a {
    21→  color: var(--color-link);
    22→  text-decoration: none;
    23→  transition: color var(--transition-fast) ease;
    24→}
    25→
    26→a:hover {
    27→  color: var(--color-link-hover);
    28→}
    29→
    30→a:focus-visible {
    31→  outline: 2px solid var(--color-focus);
    32→  outline-offset: 2px;
    33→}
    34→
    35→/* Button-like links: never underline */
    36→a[class*="btn"],
    37→a[role="button"] {
    38→  text-decoration: none;
    39→}
    40→
    41→/* ===== BUTTONS ===== */
    42→.btn {
    43→  display: inline-flex;
    44→  align-items: center;
    45→  justify-content: center;
    46→  cursor: pointer;
    47→  text-decoration: none;
    48→  border: none;
    49→  border-radius: var(--border-radius-sm);
    50→  padding: var(--space-sm) var(--space-lg);
    51→  font-family: inherit;
    52→  font-size: var(--font-size-body);
    53→  font-weight: 600;
    54→  line-height: 1;
    55→  transition:
    56→    background-color var(--transition-fast) ease,
    57→    color var(--transition-fast) ease,
    58→    opacity var(--transition-fast) ease;
    59→}
    60→
    61→.btn-primary {
    62→  background: var(--color-btn-primary);
    63→  color: var(--color-text-on-btn-primary);
    64→}
