/**
 * Global CSS
 * Reusable styles: typography, links, forms, 12-column grid
 * Safe to defer loading (non-critical path)
 */

@charset "UTF-8";

/* ===== BASE TYPOGRAPHY ===== */
p {
  font-size: var(--font-size-body);
  line-height: 1.6;
}

h1 { font-size: var(--font-size-h1); }
h2 { font-size: var(--font-size-h2); }
h3 { font-size: var(--font-size-h3); }

/* ===== LINKS ===== */
a {
  color: var(--color-link);
  text-decoration: none;
  transition: color var(--transition-fast) ease;
}

a:hover {
  color: var(--color-link-hover);
}

a:focus-visible {
  outline: 2px solid var(--color-focus);
  outline-offset: 2px;
}

/* Button-like links: never underline */
a[class*="btn"],
a[role="button"] {
  text-decoration: none;
}

/* ===== BUTTONS ===== */
.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  text-decoration: none;
  border: none;
  border-radius: var(--border-radius-sm);
  padding: var(--space-sm) var(--space-lg);
  font-family: inherit;
  font-size: var(--font-size-body);
  font-weight: 600;
  line-height: 1;
  transition:
    background-color var(--transition-fast) ease,
    color var(--transition-fast) ease,
    opacity var(--transition-fast) ease;
}

.btn-primary {
  background: var(--color-btn-primary);
  color: var(--color-text-on-btn-primary);
}

.btn-primary:hover {
  background: var(--color-btn-primary-hover);
  color: var(--color-text-on-btn-primary);
}

.btn-primary:active {
  background: var(--color-btn-primary-active);
}

.btn-secondary {
  background: var(--color-btn-secondary);
  color: var(--color-text-on-btn-secondary);
}

.btn-secondary:hover {
  background: var(--color-btn-secondary-hover);
  color: var(--color-text-on-btn-secondary);
}

.btn-secondary:active {
  background: var(--color-btn-secondary-active);
}

.btn:focus-visible {
  outline: 2px solid var(--color-focus);
  outline-offset: 2px;
}

.btn:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}

/* ===== FORMS ===== */
input:not([type="checkbox"]):not([type="radio"]),
textarea,
select {
  background: var(--color-input-bg);
  color: var(--color-input-text);
  border: 1px solid var(--color-input-border);
  border-radius: var(--border-radius-sm);
  padding: var(--space-sm) var(--space-md);
  font-family: inherit;
  font-size: var(--font-size-body);
  line-height: 1.5;
  transition:
    border-color var(--transition-fast) ease,
    box-shadow var(--transition-fast) ease;
  width: 100%;
}

input:not([type="checkbox"]):not([type="radio"]):focus,
textarea:focus,
select:focus {
  outline: none;
  border-color: var(--color-input-border-focus);
  box-shadow: 0 0 0 3px var(--color-accent);
}

input::placeholder,
textarea::placeholder {
  color: var(--color-input-placeholder);
}

input:not([type="checkbox"]):not([type="radio"]):disabled,
textarea:disabled,
select:disabled {
  background: var(--color-input-bg-disabled);
  cursor: not-allowed;
  opacity: 0.7;
}

label {
  display: block;
  font-size: var(--font-size-sm);
  color: var(--color-text-muted);
  margin-bottom: var(--space-xs);
  cursor: pointer;
}

/* ===== CHECKBOXES & RADIOS ===== */
input[type="checkbox"],
input[type="radio"] {
  -webkit-appearance: none;
  appearance: none;
  background-color: var(--color-input-bg);
  border: var(--border-width) solid var(--color-input-border);
  cursor: pointer;
  display: inline-grid;
  flex-shrink: 0;
  height: 1.125rem;
  margin: 0;
  place-content: center;
  transition:
    background-color var(--transition-fast) ease,
    border-color var(--transition-fast) ease,
    box-shadow var(--transition-fast) ease;
  width: 1.125rem;
}

input[type="checkbox"] {
  border-radius: var(--border-radius-sm);
}

input[type="radio"] {
  border-radius: 50%;
}

input[type="checkbox"]::before,
input[type="radio"]::before {
  content: "";
  transition: transform var(--transition-fast) var(--ease-in-out);
  transform: scale(0);
}

input[type="checkbox"]::before {
  background-color: var(--color-text-on-btn-primary);
  clip-path: polygon(14% 44%, 0 65%, 50% 100%, 100% 16%, 80% 0%, 43% 62%);
  height: 0.625rem;
  width: 0.625rem;
}

input[type="radio"]::before {
  background-color: var(--color-text-on-btn-primary);
  border-radius: 50%;
  height: 0.4375rem;
  width: 0.4375rem;
}

input[type="checkbox"]:checked,
input[type="radio"]:checked {
  background-color: var(--color-btn-primary);
  border-color: var(--color-btn-primary);
}

input[type="checkbox"]:checked::before,
input[type="radio"]:checked::before {
  transform: scale(1);
}

input[type="checkbox"]:focus-visible,
input[type="radio"]:focus-visible {
  border-color: var(--color-input-border-focus);
  box-shadow: 0 0 0 3px var(--color-accent);
  outline: none;
}

input[type="checkbox"]:disabled,
input[type="radio"]:disabled {
  background-color: var(--color-input-bg-disabled);
  cursor: not-allowed;
  opacity: 0.7;
}

/* .form-check — inline label + checkbox/radio pair */
.form-check {
  align-items: center;
  cursor: pointer;
  display: inline-flex;
  gap: var(--space-sm);
}

.form-check-label {
  color: var(--color-text);
  cursor: pointer;
  font-size: var(--font-size-body);
  line-height: 1.5;
  margin-bottom: 0;
}

.form-check:has(input:disabled) {
  cursor: not-allowed;
  opacity: 0.7;
}

/* ===== 12-COLUMN GRID ===== */
/* Homepage bypasses this — use .container / .row / .col-* on other pages */

.container {
  width: 100%;
  max-width: var(--container-max);
  margin-inline: auto;
  padding-inline: var(--gutter);
}

.row {
  display: grid;
  grid-template-columns: repeat(var(--grid-cols), 1fr);
  gap: var(--gutter);
}

.col-1  { grid-column: span 1;  }
.col-2  { grid-column: span 2;  }
.col-3  { grid-column: span 3;  }
.col-4  { grid-column: span 4;  }
.col-5  { grid-column: span 5;  }
.col-6  { grid-column: span 6;  }
.col-7  { grid-column: span 7;  }
.col-8  { grid-column: span 8;  }
.col-9  { grid-column: span 9;  }
.col-10 { grid-column: span 10; }
.col-11 { grid-column: span 11; }
.col-12 { grid-column: span 12; }

/* Tablet: ≤768px — collapse narrower columns */
@media (max-width: 768px) {
  .row { gap: var(--gutter-sm); }

  .col-1,
  .col-2,
  .col-3,
  .col-4 { grid-column: span 6; }

  .col-5,
  .col-6,
  .col-7,
  .col-8 { grid-column: span 12; }
}

/* Mobile: ≤480px — all columns full-width */
@media (max-width: 480px) {
  .container { padding-inline: var(--gutter-sm); }

  .col-1,
  .col-2,
  .col-3,
  .col-4,
  .col-5,
  .col-6,
  .col-7,
  .col-8,
  .col-9,
  .col-10,
  .col-11,
  .col-12 { grid-column: span 12; }
}

