/**
 * Component CSS
 * Styles for interactive and reusable UI components
 * Safe to defer loading (non-critical path)
 */

/* ===== BUTTONS ===== */
/* All buttons: always pointer, never underline */
button,
[role="button"] {
  cursor: pointer;
  text-decoration: none;
}

button:hover {
  opacity: 0.9;
}

button:active {
  opacity: 0.8;
}

button:focus-visible {
  outline: 2px solid var(--color-focus);
  outline-offset: 2px;
}

/* Canvas animation container */
canvas {
  width: 32px;
  height: 32px;
}

/* ===== HEADER ===== */
header {
  width: 100%;
  padding: var(--space-md) var(--space-xl);
  background-color: var(--color-bg);
  border-bottom: var(--border-width) solid var(--color-border);
  display: flex;
  align-items: center;
  justify-content: center;
}

header a {
  display: flex;
  align-items: center;
  justify-content: center;
  color: inherit;
  text-decoration: none;
  transition: opacity var(--transition-fast) ease;
}

header a:hover {
  opacity: 0.8;
}

header a:focus-visible {
  outline: 2px solid var(--color-focus);
  outline-offset: 2px;
}

/* SVG Logo */
.logo {
  height: 60px;
  width: auto;
  max-width: 400px;
  display: block;
}

/* Responsive header */
@media (max-width: 768px) {
  header { padding: 0.75rem 1.5rem; }
  .logo  { height: 50px; }
}

@media (max-width: 480px) {
  header { padding: 0.5rem 1rem; }
  .logo  { height: 40px; }
}

