/**
 * Utilities CSS
 * Helper classes and utility styles for common patterns
 * Ready for future expansion with Tailwind or custom utilities
 */

/* Margin utilities */
.m-0 {
  margin: 0;
}

.p-0 {
  padding: 0;
}

/* Display utilities */
.flex {
  display: flex;
}

.flex-center {
  display: flex;
  align-items: center;
  justify-content: center;
}

/* Visibility utilities */
.sr-only {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  white-space: nowrap;
  border-width: 0;
}

/**
 * Typography & Google Fonts
 * ==========================
 * Imports custom Google Fonts and defines font family custom properties
 * Uses display=swap to prioritize content visibility during font load
 */

/* Import Google Fonts: Roboto Bold and Open Sans Regular */
/* display=swap ensures text is visible while fonts load asynchronously */
@import url('https://fonts.googleapis.com/css2?family=Roboto:wght@700&family=Open+Sans:wght@400&display=swap');

:root {
  /* ===== FONT FAMILIES ===== */

  /* Heading Font - Roboto Bold */
  /* Used for: H1, H2, headers, prominent text */
  /* Weight: 700 (bold) */
  --font-family-heading: 'Roboto', sans-serif;

  /* Body Font - Open Sans Regular */
  /* Used for: paragraphs, body text, general content */
  /* Weight: 400 (regular) */
  --font-family-body: 'Open Sans', sans-serif;

  /* Fallback serif font for legacy compatibility */
  --font-family-serif: Georgia, 'Times New Roman', serif;
}

/* ===== FONT USAGE ===== */

/* Apply heading font to heading elements */
h1,
h2,
h3,
h4,
h5,
h6 {
  font-family: var(--font-family-heading);
  font-weight: 700;
}

/* Apply body font to main content */
body,
p,
a,
li {
  font-family: var(--font-family-body);
  font-weight: 400;
}

/* ===== BANNER TEXT ===== */

/* Banner heading text (H2 for "eruditorum.org") */
.banner-txt {
  font-family: var(--font-family-heading);
  font-weight: 700;
}

