   230→      lerpA(f1, to[i][0], p),
   231→      lerpA(f2, to[i][1], p),
   232→    ]);
   233→  }
   234→
   235→  // ── Main loop ─────────────────────────────────────────────────────────────
   236→  // Full cycle (30 s):
   237→  //   0 → TRANS_DUR          reverse ease: time display → pattern
   238→  //   TRANS_DUR → TRANS_START blended patterns
   239→  //   TRANS_START → PATTERN_END forward ease: pattern → time display
   240→  //   PATTERN_END → CYCLE     static time display
   241→  const t0 = Date.now();
   242→  let transFrom  = null;  // pattern snapshot for pattern→time ease
   243→  let timeSnap   = null;  // time snapshot for time→pattern reverse ease
   244→  let lastSec    = -1;    // throttle static display to once per second
   245→
   246→  function tick() {
   247→    const now           = Date.now();
   248→    const countdownDone = cfg.mode === 'countdown' && cfg.countdownEnd > 0 && now >= cfg.countdownEnd;
   249→    const pos           = (DEBUG_DIGITS || countdownDone) ? PATTERN_END : (now - t0) % CYCLE;
   250→    const t             = (now - t0) / 1000;
   251→
   252→    if (pos < TRANS_DUR) {
   253→      // Reverse ease: time display angles → live pattern
   254→      if (!timeSnap) timeSnap = timeAngles().map(([a, b]) => [norm(a), norm(b)]);
   255→      transFrom = null;
   256→      const p      = ease(pos / TRANS_DUR);
   257→      const target = blendedPatternAngles(t, pos);
   258→      apply(timeSnap.map(([f1, f2], i) => [
   259→        lerpA(f1, target[i][0], p),
   260→        lerpA(f2, target[i][1], p),
   261→      ]));
   262→
   263→    } else if (pos < TRANS_START) {
   264→      // Pure pattern display
   265→      timeSnap  = null;
   266→      transFrom = null;
   267→      apply(blendedPatternAngles(t, pos));
   268→
   269→    } else if (pos < PATTERN_END) {
   270→      // Forward ease: pattern → time display
   271→      timeSnap = null;
   272→      if (!transFrom) {
   273→        transFrom = blendedPatternAngles(t, TRANS_START - 1).map(([a, b]) => [norm(a), norm(b)]);
   274→      }
   275→      const p      = ease((pos - TRANS_START) / TRANS_DUR);
   276→      const target = timeAngles();
   277→      apply(transFrom.map(([f1, f2], i) => [
   278→        lerpA(f1, target[i][0], p),
   279→        lerpA(f2, target[i][1], p),
   280→      ]));
   281→
   282→    } else {
   283→      // Static time display — re-render once per second only
   284→      timeSnap  = null;
   285→      transFrom = null;
   286→      const sec = Math.floor(now / 1000);
   287→      if (sec !== lastSec) { lastSec = sec; apply(timeAngles()); }
   288→    }
   289→
   290→    requestAnimationFrame(tick);
   291→  }
   292→
   293→  tick();
   294→})();
