     1→/**
     2→ * Animated Border Effect
     3→ * =======================
     4→ * Creates a rotating conic gradient border effect on hover
     5→ * Uses CSS variables for easy customization
     6→ * Animated border traces from primary brand color
     7→ */
     8→
     9→/* Center container for button */
    10→.center-box {
    11→  height: 100vh;
    12→  width: 100%;
    13→  display: flex;
    14→  justify-content: center;
    15→  align-items: center;
    16→  position: relative;
    17→}
    18→
    19→/* Animated border box - creates the glow/outline effect */
    20→.effect-animate-border,
    21→.effect-animate-border + button {
    22→  max-height: 200px;
    23→  max-width: 250px;
    24→  height: 100%;
    25→  width: 100%;
    26→  position: absolute;
    27→  overflow: hidden;
    28→  z-index: 0;
    29→  /* Border styling from CSS variables */
    30→  border-radius: var(--border-radius);
    31→}
    32→
    33→/* Blur filter for glow effect */
    34→.effect-animate-border {
    35→  overflow: hidden;
    36→  filter: blur(var(--border-blur));
    37→}
    38→
    39→/* Rotating gradient for border animation */
    40→.effect-animate-border:before,
    41→.effect-animate-border + button:before {
    42→  content: '';
    43→  z-index: -2;
    44→  text-align: center;
    45→  top: 50%;
    46→  left: 50%;
    47→  transform: translate(-50%, -50%) rotate(0deg);
    48→  position: absolute;
    49→  width: 99999px;
    50→  height: 99999px;
    51→  background-repeat: no-repeat;
    52→  background-position: 0 0;
    53→  /* Conic gradient using primary brand color for border */
    54→  background-image: conic-gradient(
    55→    rgba(0, 0, 0, 0),
    56→    var(--color-primary),
    57→    rgba(0, 0, 0, 0) 25%
    58→  );
    59→  /* Rotate animation - duration from CSS variable */
    60→  animation: rotate var(--animation-duration) linear infinite;
    61→}
    62→
    63→/* Inner border cleanup */
    64→.effect-animate-border:after {
    65→  content: '';
    66→  position: absolute;
    67→  z-index: -1;
    68→  /* Border width from CSS variable */
    69→  left: var(--border-width);
