/**
 * Design System — Colors, Spacing, Typography
 * ============================================
 * Light / dark mode via prefers-color-scheme.
 * Override with [data-theme="light"] or [data-theme="dark"] on <html>.
 */

/* ===== LIGHT MODE (default) ===== */
:root {
  /* ── Surfaces ── */
  --color-bg:           #ffffff;
  --color-bg-alt:       #f4f5f5;
  --color-bg-raised:    #ffffff;

  /* ── Text ── */
  --color-text:         #141211;
  --color-text-muted:   #555e64;
  --color-text-on-btn:  #141211;   /* text on ghost/outline buttons */

  /* ── Borders ── */
  --color-border:       #262c30;
  --color-border-subtle: rgba(38, 44, 48, 0.25);

  /* ── Primary button ── */
  --color-btn-primary:        #052842;
  --color-btn-primary-hover:  #083d65;
  --color-btn-primary-active: #031a2b;
  --color-text-on-btn-primary: #ffffff;

  /* ── Secondary button ── */
  --color-btn-secondary:        #074020;
  --color-btn-secondary-hover:  #0a5c2d;
  --color-btn-secondary-active: #052e17;
  --color-text-on-btn-secondary: #ffffff;

  /* ── Links ── */
  --color-link:       #052842;
  --color-link-hover: #083d65;

  /* ── Forms ── */
  --color-input-bg:           #ffffff;
  --color-input-bg-disabled:  #eceef0;
  --color-input-border:       #262c30;
  --color-input-border-focus: #052842;
  --color-input-text:         #141211;
  --color-input-placeholder:  #7a8590;

  /* ── Focus ring ── */
  --color-focus: #052842;

  /* ── Accent / highlight ── */
  --color-accent:       rgba(5, 40, 66, 0.08);
  --color-accent-hover: rgba(5, 40, 66, 0.14);

  /* ── Legacy aliases (used by existing code) ── */
  --color-bg-dark:      #141211;
  --color-text-light:   #e6ecf0;
  --color-primary:      #052842;
  --color-secondary:    #074020;
  --color-neutral:      #141211;
  --color-gradient-start: #c7f0fe;
  --color-gradient-end:   #56d3c9;
  --border-color: var(--color-border);

  /* ===== TYPOGRAPHY ===== */
  /* Based on browser-default 1rem = 16px */
  --font-size-h1:   2rem;      /* 32px */
  --font-size-h2:   1.5rem;    /* 24px */
  --font-size-h3:   1.25rem;   /* 20px */
  --font-size-body: 1rem;      /* 16px */
  --font-size-sm:   0.875rem;  /* 14px */
  --font-size-xs:   0.75rem;   /* 12px */
  --font-family-heading: 'Roboto', sans-serif;
  --font-family-body:    'Open Sans', sans-serif;
  --font-family-mono:    'Courier New', Courier, monospace;

  /* ===== BORDERS & EFFECTS ===== */
  --border-width:      2px;
  --border-radius-sm:  4px;
  --border-radius:     8px;
  --border-radius-lg:  16px;
  --border-blur:       20px;
  --animation-duration: 4s;

  /* ===== SPACING ===== */
  --space-xs:  0.25rem;   /*  4px */
  --space-sm:  0.5rem;    /*  8px */
  --space-md:  1rem;      /* 16px */
  --space-lg:  1.5rem;    /* 24px */
  --space-xl:  2rem;      /* 32px */
  --space-2xl: 3rem;      /* 48px */
  --space-3xl: 4rem;      /* 64px */

  /* ===== 12-COLUMN GRID ===== */
  --grid-cols:     12;
  --gutter:        2.4rem;   /* column gap */
  --gutter-sm:     1.2rem;   /* mobile gap */
  --container-max: 1200px;

  /* ===== TRANSITIONS ===== */
  --transition-fast:   0.2s;
  --transition-normal: 0.4s;
  --transition-slow:   0.6s;
  --ease-in-out: cubic-bezier(0.4, 0, 0.2, 1);
  --ease-out:    cubic-bezier(0, 0, 0.2, 1);
  --ease-in:     cubic-bezier(0.4, 0, 1, 1);
}

/* ===== DARK MODE (system preference) ===== */
@media (prefers-color-scheme: dark) {
  :root {
    --color-bg:           #141211;
    --color-bg-alt:       #1e1c1a;
