/* Apply heading font to heading elements */
h1,
h2,
h3,
h4,
h5,
h6 {
  font-family: var(--font-family-heading);
  font-weight: 700;
}

/* Apply body font to main content */
body,
p,
a,
li {
  font-family: var(--font-family-body);
  font-weight: 400;
}

/* ===== BANNER TEXT ===== */

/* Banner heading text (H2 for "eruditorum.org") */
.banner-txt {
  font-family: var(--font-family-heading);
  font-weight: 700;
}

