/**
 * border-effect.css — Animated Conic Gradient Border
 * =====================================================
 * Creates a rotating conic-gradient border effect using CSS animations.
 * Uses CSS custom properties for easy customisation.
 *
 * Usage:
 *   <div class="border-effect-wrap">
 *     <div class="border-effect" aria-hidden="true"></div>
 *     <button class="border-effect-btn">Label</button>
 *   </div>
 *
 * The .border-effect element is purely decorative (aria-hidden).
 * The adjacent button sits above it via z-index.
 */

/* ===== WRAPPER ===== */
.border-effect-wrap {
    align-items: center;
    display: flex;
    justify-content: center;
    position: relative;
}

/* ===== SHARED: glow layer + button ===== */
.border-effect,
.border-effect-btn {
    border-radius: var(--border-radius);
    height: 100%;
    max-height: 7.5rem;     /* 120px */
    max-width: 8.75rem;     /* 140px */
    overflow: hidden;
    position: absolute;
    width: 100%;
}

/* ===== GLOW LAYER ===== */
/* Blurred version — creates the outer glow effect */
.border-effect {
    filter: blur(var(--border-blur));
    z-index: 0;
}

/* Rotating conic gradient — shared by glow and clean border layers */
.border-effect::before,
.border-effect-btn::before {
    animation: border-effect-rotate var(--animation-duration) linear infinite;
    background-image: conic-gradient(
        rgb(0 0 0 / 0),
        var(--color-btn-primary),
        rgb(0 0 0 / 0) 25%
    );
    background-position: 0 0;
    background-repeat: no-repeat;
    content: '';
    height: 99999px;
