/**
 * Critical CSS
 * Above-the-fold styles loaded immediately
 * Contains core layout for optimal paint performance
 */

/* Reset */
*,
*::before,
*::after {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

html {
  /* Browser default: 1rem = 16px */
  font-size: 100%;
  height: 100%;
}

body {
  min-height: 100%;
  font-size: var(--font-size-body, 1rem);
  line-height: 1.6;
  background: var(--color-bg);
  color: var(--color-text);
  font-family: var(--font-family-body, sans-serif);
  margin: 0;
}

html,
body {
  height: 100%;
}

/* Main container */
main {
  display: flex;
  height: 100%;
  width: auto;
  padding: 0;
  margin: 0;
  align-items: center;
  justify-content: center;
}

/* Button base */
button {
  cursor: pointer;
  border: none;
  background: none;
  font: inherit;
  text-decoration: none;
  transition: opacity var(--transition-fast, 0.2s) ease;
}


button:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}

/* Responsive images */
img {
  border: 0;
  width: 100%;
  height: auto;
  display: block;
}

/* Hidden canvas (favicon animator) */
canvas {
  position: absolute;
  visibility: hidden;
}

