    align-items: center;
    background: var(--ctrl-accent);
    border: none;
    border-radius: 3px;
    color: #ffffff;
    cursor: pointer;
    display: inline-flex;
    font-family: inherit;
    font-size: 0.85rem;
    gap: 0.4rem;
    letter-spacing: 0.06em;
    margin-top: 0.75rem;
    padding: 0.55rem 1.4rem;
    text-decoration: none;
    transition: background 0.2s ease;
}

.ctrl-btn:hover  { background: var(--ctrl-accent-hover); }
.ctrl-btn:active { background: var(--ctrl-accent-active); }

.ctrl-btn:focus-visible {
    outline: 2px solid var(--ctrl-border-focus);
    outline-offset: 2px;
}

/* ===== NOTES ===== */
.ctrl-note {
    color: var(--ctrl-text-dim);
    font-size: 0.72rem;
    line-height: 1.5;
    margin-top: 0.6rem;
}

/* ===== STATUS ===== */
.ctrl-status {
    color: var(--ctrl-status);
    font-size: 0.78rem;
    margin-top: 0.5rem;
    min-height: 1.2em;
}

/* ===== STATE ===== */
.is-hidden { display: none; }

