/**
 * components.css — Reusable UI Components
 * ==========================================
 * Header, logo, and other shared UI components.
 * Mobile-first: base styles for smallest screen; min-width queries upward.
 *
 * Load order: after global.css, before page-specific CSS.
 */

/* ===== HEADER ===== */
/* Mobile base */
header {
    align-items: center;
    background-color: var(--color-bg);
    border-bottom: var(--border-width) solid var(--color-border);
    display: flex;
    justify-content: center;
    padding: var(--space-sm) var(--space-md);
    width: 100%;
}

header a {
    align-items: center;
    color: inherit;
    display: flex;
    justify-content: center;
    text-decoration: none;
    transition: opacity var(--transition-fast) ease;
}

header a:hover { opacity: 0.8; }

header a:focus-visible {
    outline: 2px solid var(--color-focus);
    outline-offset: 2px;
}

/* ===== LOGO ===== */
/* Mobile base */
.logo {
    display: block;
    height: 2.5rem;     /* 40px */
    max-width: 400px;
    width: auto;
}

@media (min-width: 480px) {
    header { padding: 0.75rem 1.5rem; }
    .logo  { height: 3.125rem; }  /* 50px */
}

@media (min-width: 768px) {
    header { padding: var(--space-md) var(--space-xl); }
    .logo  { height: 3.75rem; }   /* 60px */
}

/* ===== MAIN LAYOUT ===== */
/* Non-clock pages: flex column, no fixed height */
main {
    display: flex;
    flex-direction: column;
    min-height: calc(100vh - 6rem); /* approximate header clearance */
    padding: var(--space-xl) 0;
    width: 100%;
    position: relative;
}

aside.side {
    position: absolute;
    transform: rotateX(-90deg);
    right: 0;
    top: 200px;
}

aside.side p {
    display: inline-block;
}

