    background: var(--color-bg-raised);
    border: 1px solid var(--color-border-subtle);
    border-radius: var(--border-radius);
    max-height: 90vh;
    max-width: 36rem;
    overflow-y: auto;
    padding: var(--space-xl);
    position: relative;
