    if (now - lastFrame < PATTERN_FRAME_MS) return;
    lastFrame = now;
    timeSnap  = null;
    transFrom = null;
    apply(blendedPatternAngles(t, pos));

  } else if (pos < PATTERN_END) {
    // Forward ease: pattern → time display (60 fps — short 2 s window)
